import React from 'react';
import Accordion from 'react-bootstrap/Accordion';

function CollapsedText({ name, text, buttonComponent, section }) {
  // Función para manejar el clic en el encabezado del acordeón
  const handleAccordionClick = () => {
    if (section) {
      const sectionElement = document.querySelector(section);
      if (sectionElement) {
        const navbarHeight = document.querySelector('.navbar').offsetHeight;
        const sectionPosition = sectionElement.offsetTop - navbarHeight;
        window.scrollTo({
          top: sectionPosition,
          behavior: 'smooth' // Desplazamiento suave
        });
      }
    }
  };

  return (
    <Accordion>
      <Accordion.Item eventKey="0">
        <Accordion.Header onClick={handleAccordionClick}>{name}</Accordion.Header>
        <Accordion.Body>
          {text}
          {buttonComponent}
        </Accordion.Body>
      </Accordion.Item>
    </Accordion>
  );
}

export default CollapsedText;
